sparql_query:
PREFIX goo:    <https://ucf-henat.github.io/GeoOutageOnto/#>
PREFIX gokg:   <http://example.org/resource#>
PREFIX schema: <http://schema.org/>
PREFIX xsd:    <http://www.w3.org/2001/XMLSchema#>
PREFIX rdf:    <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs:   <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?cyclone ?name ?start ?end ?maxSustainedWindSpeed
WHERE {
  VALUES ?basin { "ATL"^^xsd:string "EPAC"^^xsd:string "CPAC"^^xsd:string }
  BIND(160 AS ?extremelyPowerfulWindThreshold)
  ?cyclone a goo:HurricaneEventRecord ;
           schema:name ?name ;
           goo:basin ?basin ;
           goo:eventStartTime ?start ;
           goo:eventEndTime ?end ;
           goo:maxSustainedWindSpeed ?maxSustainedWindSpeed .
  FILTER (?maxSustainedWindSpeed >= ?extremelyPowerfulWindThreshold)
  FILTER ((?end - ?start) > "P3D"^^xsd:dayTimeDuration)
}
ORDER BY DESC(?maxSustainedWindSpeed) ?start
LIMIT 10
